      final model = CalculatorModel();
      model.inputDigit('1');
      model.inputDigit('0');
      model.inputOperator('÷');
      model.inputDigit('2');
      model.calculate();
      expect(model.display, '5');
    });

    test('CalculatorModel calculate division by zero', () {
      final model = CalculatorModel();
      model.inputDigit('5');
      model.inputOperator('÷');
      model.inputDigit('0');
      model.calculate();
      expect(model.display, 'Error');
    });

    test('CalculatorModel calculatePercent works', () {
