    });

    test('IntervalTimerModel applyPreset works', () {
      final model = IntervalTimerModel();
      model.applyPreset(model.presets[0]);
      expect(model.workDuration, 20);
      expect(model.restDuration, 10);
      expect(model.sets, 8);
