  group('Bitwise Calculator Provider tests', () {
    setUpAll(() {
      SharedPreferences.setMockInitialValues({});
      TestWidgetsFlutterBinding.ensureInitialized();
    });

    test('providerBitwise exists', () {
      expect(providerBitwise, isNotNull);
