      for (int i = 0; i < 3; i++) {
        model.generateNewProblem();
        model.updateInput('${model.currentProblem!.answer}');
        model.submitAnswer();
      }
      expect(model.currentStreak, 3);
      expect(model.bestStreak, 3);
      
      model.generateNewProblem();
      model.updateInput('${model.currentProblem!.answer + 1}');
